#include <iostream>

// cout: الإخراج العادي → stdout (مُخزّن مؤقتًا)
// cerr: الأخطاء → stderr (غير مُخزّن، يظهر فورًا)
// clog: السجل → stderr (مُخزّن مؤقتًا)

// ✅ cout للنتائج العادية
std::cout << "Result: 42" << '\n';

// ✅ cerr للأخطاء التي تحتاج ظهورًا فوريًا
std::cerr << "ERROR: file not found" << '\n';

// ✅ clog للسجل الذي لا يحتاج ظهورًا فوريًا
std::clog << "[INFO] cache miss" << '\n';

