#include <iostream>
#include <fstream>

int main() {
    std::fstream db("db.bin", std::ios::in | std::ios::out | std::ios::binary);
    if (!db) {
        db.open("db.bin", std::ios::out | std::ios::binary);
        db.close();
        db.open("db.bin", std::ios::in | std::ios::out | std::ios::binary);
    }
    int record = 42;
    db.seekp(0);
    db.write(reinterpret_cast<char*>(&record), sizeof(record));
    db.seekg(0);
    db.read(reinterpret_cast<char*>(&record), sizeof(record));
    std::cout << "القيمة: " << record << std::endl;
    return 0;
}

