#include <iostream>
#include <random>

int main() {
    std::mt19937 rng(std::random_device{}());
    std::bernoulli_distribution critical_hit(0.15); // 15% ضربة حرجة

    int damage = 10;
    if (critical_hit(rng)) {
        damage *= 2;
        std::cout << "ضربة حرجة! الضرر: " << damage << '\n';
    } else {
        std::cout << "ضربة عادية. الضرر: " << damage << '\n';
    }
}

