#include <iostream>
#include <random>
#include <map>

int main() {
    std::mt19937 rng(std::random_device{}());
    std::poisson_distribution<int> customers(4.0); // متوسط 4 عملاء/ساعة

    std::map<int, int> histogram;
    for (int i = 0; i < 10000; i++) {
        histogram[customers(rng)]++;
    }
    for (auto [count, freq] : histogram) {
        std::cout << count << " عملاء: " << std::string(freq / 50, '*') << '\n';
    }
}

#include <iostream>
#include <random>

int main() {
    std::mt19937 rng(std::random_device{}());
    std::poisson_distribution<int> errors(1.5); // متوسط 1.5 خطأ/صفحة

    int total_errors = 0;
    for (int page = 0; page < 100; page++) {
        int page_errors = errors(rng);
        total_errors += page_errors;
    }
    std::cout << "إجمالي الأخطاء في 100 صفحة: " << total_errors << '\n';
    // ≈ 150 خطأ
}

#include <iostream>
#include <random>

int main() {
    std::mt19937 rng(std::random_device{}());

    // التوزيع المنتظم: كل قيمة متساوية الاحتمال
    std::uniform_int_distribution<int> uniform(0, 8);

    // بواسون: القيم القريبة من المتوسط أكثر احتمالًا
    std::poisson_distribution<int> poisson(4.0);

    std::cout << "Uniform: ";
    for (int i = 0; i < 10; i++) std::cout << uniform(rng) << " ";

    std::cout << "\nPoisson:  ";
    for (int i = 0; i < 10; i++) std::cout << poisson(rng) << " ";
}

