#include <iostream>
#include <regex>
#include <string>

int main() {
    std::string text = "cpp is great. cpp is modern. I love cpp.";
    std::regex word("cpp");

    auto begin = std::sregex_iterator(text.begin(), text.end(), word);
    auto end = std::sregex_iterator();

    int count = 0;
    for (auto it = begin; it != end; ++it) {
        count++;
        std::cout << "تطابق " << count << ": " << (*it)[0] << "\n";
    }
    std::cout << "الإجمالي: " << count << '\n'; // 3
}

#include <iostream>
#include <regex>
#include <string>
#include <vector>

int main() {
    std::string text = "age:25, height:180cm, weight:75kg";
    std::regex num_pattern("\\d+");

    std::vector<int> numbers;
    auto begin = std::sregex_iterator(text.begin(), text.end(), num_pattern);
    auto end = std::sregex_iterator();

    for (auto it = begin; it != end; ++it) {
        numbers.push_back(std::stoi((*it)[0].str()));
    }
    // numbers = {25, 180, 75}
    for (int n : numbers) std::cout << n << " ";
}

#include <iostream>
#include <regex>
#include <string>

int main() {
    std::string html = "<a href='https://a.com'>A</a> <a href='https://b.com'>B</a>";
    std::regex link_pattern("href='([^']+)'");

    auto begin = std::sregex_iterator(html.begin(), html.end(), link_pattern);
    auto end = std::sregex_iterator();

    for (auto it = begin; it != end; ++it) {
        std::cout << "رابط: " << (*it)[1] << '\n';
        // [1] = المجموعة الفرعية الأولى (بين الأقواس)
    }
    // رابط: https://a.com
    // رابط: https://b.com
}

#include <iostream>
#include <regex>
#include <string>

int main() {
    std::string csv = "red,green,blue,yellow";
    std::regex comma(",");

    // -1 يعني: أرجع النصوص بين التطابقات (التقسيم)
    auto begin = std::sregex_token_iterator(csv.begin(), csv.end(), comma, -1);
    auto end = std::sregex_token_iterator();

    for (auto it = begin; it != end; ++it) {
        std::cout << *it << '\n';
    }
    // red
    // green
    // blue
    // yellow
}

#include <iostream>
#include <regex>
#include <string>

int main() {
    std::string text = "name:Ali age:25 city:Cairo";
    std::regex kv_pattern("(\\w+):(\\w+)");

    // 2 = أرجع المجموعة الفرعية الثانية (القيمة) فقط
    auto begin = std::sregex_token_iterator(text.begin(), text.end(), kv_pattern, 2);
    auto end = std::sregex_token_iterator();

    for (auto it = begin; it != end; ++it) {
        std::cout << "قيمة: " << *it << '\n';
    }
    // قيمة: Ali
    // قيمة: 25
    // قيمة: Cairo
}

#include <iostream>
#include <regex>
#include <string>
#include <vector>

int main() {
    std::string text = "2024-03-15 2023-11-20";
    std::regex date_pattern("(\\d{4})-(\\d{2})-(\\d{2})");

    // {1, 3} = أرجع المجموعتين الأولى والثالثة (سنة + يوم)
    std::vector<int> groups = {1, 3};
    auto begin = std::sregex_token_iterator(
        text.begin(), text.end(), date_pattern, groups);
    auto end = std::sregex_token_iterator();

    for (auto it = begin; it != end; ++it) {
        std::cout << *it << '\n';
    }
    // 2024
    // 15
    // 2023
    // 20
}

