class LineCounter {
    static int idx;
public:
    static void init() { idx = std::cout.xalloc(); std::cout.iword(idx) = 0; }
    static std::ostream& count(std::ostream& os) {
        os.iword(idx)++;
        os << "[" << os.iword(idx) << "] ";
        return os;
    }
};
int LineCounter::idx = 0;

std::ostream& operator<<(std::ostream& os, decltype(LineCounter::count)& manip) {
    return manip(os);
}

int main() {
    LineCounter::init();
    std::cout << LineCounter::count << "سطر أول\n";
    std::cout << LineCounter::count << "سطر ثانٍ\n";
