#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::ifstream file("data.txt");
    std::string line;
    while (std::getline(file, line)) {
        std::cout << line << std::endl;
    }
    file.clear();
    file.seekg(0, std::ios::beg);
    int count = 0;
    while (std::getline(file, line)) count++;
    std::cout << "عدد الأسطر: " << count << std::endl;
    return 0;
}

