#include <iostream>

int main() {
    double pi = 3.14159265358979;
    std::cout.setf(std::ios::fixed, std::ios::floatfield);
    std::cout.precision(4);
    std::cout << "ثابت: " << pi << std::endl;
    std::cout.setf(std::ios::scientific, std::ios::floatfield);
    std::cout.precision(2);
